func TestEnumEntityEventPayloadEventType(t *testing.T) {
	t.Run("NewFromString_CREATED", func(t *testing.T) {
		t.Parallel()
		val, err := NewEntityEventPayloadEventTypeFromString("CREATED")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, EntityEventPayloadEventType("CREATED"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_UPDATED", func(t *testing.T) {
		t.Parallel()
		val, err := NewEntityEventPayloadEventTypeFromString("UPDATED")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, EntityEventPayloadEventType("UPDATED"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_DELETED", func(t *testing.T) {
		t.Parallel()
		val, err := NewEntityEventPayloadEventTypeFromString("DELETED")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, EntityEventPayloadEventType("DELETED"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_PREEXISTING", func(t *testing.T) {
		t.Parallel()
		val, err := NewEntityEventPayloadEventTypeFromString("PREEXISTING")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, EntityEventPayloadEventType("PREEXISTING"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_Invalid", func(t *testing.T) {
		_, err := NewEntityEventPayloadEventTypeFromString("invalid_value_that_does_not_exist")
		assert.Error(t, err)
	})

	t.Run("Ptr", func(t *testing.T) {
		val, err := NewEntityEventPayloadEventTypeFromString("CREATED")
		assert.NoError(t, err)
		ptr := val.Ptr()
		assert.NotNil(t, ptr)
		assert.Equal(t, val, *ptr)
	})
}

